span.t-attf-class:
badge #{
                                        item.priority == 'vhi' and 'bg-danger' or
                                        item.priority == 'hi' and 'bg-warning' or
                                        item.priority == 'med' and 'bg-info' or
                                        item.priority == 'lo' and 'bg-secondary' or 'bg-light text-dark'
                                    }

badge #{
                                        item.status == 'done' and 'bg-success' or
                                        item.status == 'in_progress' and 'bg-primary' or
                                        item.status == 'canceled' and 'bg-danger' or 'bg-secondary'
                                    }
